try {
  let aiData = $input.item.json.message?.content || $input.item.json.content || $input.item.json.text;

  // Если ИИ уже отдал готовый объект, то просто пробрасываем его дальше
  if (typeof aiData === 'object' && aiData !== null) {
    return [{ json: aiData }];
  }

  // Если отдал как текст с мусором - чистим и парсим
  const cleanText = aiData.replace(/```json/g, '').replace(/```/g, '').trim();
  return [{ json: JSON.parse(cleanText) }];

} catch (e) {
  return [{ json: { selected_id: "NO_NEWS", post_text: "Ошибка парсинга" } }];
}

