const searchData = $('When Executed by Another Workflow').first().json;
const tweets = searchData.data || [];
const users = searchData.includes?.users || []; // Тянем юзернеймы

// 1. Убираем дубликаты (баяны из Google Sheets)
let postedIds = [];
try {
  postedIds = $input.all().map(item => item.json.tweet_id).filter(id => id);
} catch (e) {}

// ------------------------------------------------------------------
// Чистим текст до "смыслового" содержимого.
// Цель: отрезать твиты, где есть только @mentions, ссылки, хэштеги, тикеры, эмодзи или мусорные CTA.
// ------------------------------------------------------------------

function cleanMeaningfulText(text) {
  return (text || '')
    .replace(/https?:\/\/\S+/g, ' '
    .replace(/(^|\s)@\w+/g, ' '
    .replace(/(^|\s)#\w+/g, ' ')
    .replace(/(^|\s)\$[A-Za-z][A-Za-z0-9_]{0,15}\b/g, ' ')
    .replace(/[^\p{L}\p{N}\s]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function getMeaningfulWordCount(text) {
  const cleaned = cleanMeaningfulText(text);
  return (cleaned.match(/[\p{L}\p{N}]{2,}/gu) || []).length;
}

function getMentionCount(text) {
  return ((text || '').match(/(^|\s)@\w+/g) || []).length;
}

function getUrlCount(text) {
  return ((text || '').match(/https?:\/\/\S+/g) || []).length;
}

function getTickerCount(text) {
  return ((text || '').match(/\$[A-Za-z][A-Za-z0-9_]{0,15}\b/g) || []).length;
}

// ------------------------------------------------------------------
// Главный junk-фильтр.
// Он режет:
// - пустые/почти пустые твиты
// - твиты только из упоминаний + ссылок
// - Telegram/реферальный спам
// - примитивный призывы для взаимодействия
// - слишком короткие тексты без фактуры
// ------------------------------------------------------------------

function isJunkTweet(tweet) {
  const text = tweet.text || '';
  const raw = text.trim();
  const meaningfulWordCount = getMeaningfulWordCount(text);
  const mentionCount = getMentionCount(text);
  const urlCount = getUrlCount(text);
  const tickerCount = getTickerCount(text);

  if (raw.length < 3) return true;

  // Пример вида: "@saylor @BTCFoundation @titlejt https://t.co/..."
  // После удаления mentions/links/tickers не остаётся смыслового текста.
  const onlyEntitiesAndLinks =
    meaningfulWordCount < 2 && (mentionCount > 0 || urlCount > 0 || tickerCount > 0);

  if (onlyEntitiesAndLinks) return true;

  // Явный спам.
  const isTelegramSpam =
    /link in bio|telegram|follow along|entry and exit|exact chart|closed another trade|clean \+\d{2,4}% profit|\+\d{2,4}% profit|deposit \$?\d+|cashback|sign up with my link/i.test(text);

  if (isTelegramSpam) return true;

  // Дешёвая работа на публику без полезной фактуры.
  const isPureEngagementBait =
    /are you buying|holding or out|pick one|thoughts\?|agree\?|yes or no|👇/i.test(text)
    && meaningfulWordCount < 10;

  if (isPureEngagementBait) return true;

  // Текст, который состоит почти только из обращения и короткой эмоции.
  // Пример: "@user based", "@user lol", "@user true".
  const isTinyReply =
    mentionCount > 0 &&
    meaningfulWordCount < 3 &&
    raw.length < 60;

  if (isTinyReply) return true;

  return false;
}

// ------------------------------------------------------------------
// freshTweets теперь не просто "не дубли", а "не дубли + не мусор".

const freshTweets = tweets
  .filter(t => !postedIds.includes(t.id))
  .filter(t => !isJunkTweet(t));

if (freshTweets.length === 0) {
  return [{
    json: {
      new_story_found: false,
      reason: 'No fresh non-junk tweets found'
    }
  }];
}

// 2. Тема и Оценка

function getTopic(text) {
  const lower = (text || '').toLowerCase();

  if (lower.match(/hack|hacked|exploit|breach|stolen|scam|rug pull|rugpull|vulnerability|attack|compromised/i)) return 'scandal';

  if (lower.match(/memecoin|meme coin|pepe|doge|shib|bonk|floki|wojak|wen|baby|inu\b/i)) return 'memecoin';

  const tickers = (text || '').match(/\$[A-Z]{3,6}/g) || [];
  const hasAltcoin = tickers.some(ticker => !ticker.match(/\$(BTC|ETH|USDT|USDC|BUSD)/i));

  if (
    hasAltcoin ||
    lower.match(/solana|cardano|polkadot|avalanche|polygon|chainlink|uniswap|ripple|xrp|\$sol\b|\$ada\b|\$dot\b|\$avax\b|\$matic\b|\$link\b|\$uni\b/i)
  ) return 'altcoin';

  if (lower.match(/ath|all-time high|all time high|record high|new high|highest ever|historic high/i)) return 'ath';

  if (lower.match(/etf|exchange.traded.fund|spot etf|bitcoin etf|ethereum etf/i)) return 'etf';

  if (lower.match(/whale|whales|large holder|top wallet|major holder|dormant wallet|wallet moves|massive transfer/i)) return 'whale';

  if (lower.match(/sec|cftc|regulation|regulated|lawsuit|sued|banned|ban |legal|court|judge|fine|penalty|compliance/i)) return 'regulation';

  // Важно: Saylor по-прежнему может быть institutional,
  // но твиты только с упоминаниями от @saylor уже будут отрезаны мусорным-фильтром выше.
  if (lower.match(/microstrategy|saylor|blackrock|grayscale|fidelity|tesla|institutional|institutions buy|corporate treasury|wall street/i)) return 'institutional';

  if (lower.match(/listing|listed|lists|delist|binance listing|coinbase listing|kraken listing|new pair/i)) return 'listing';

  if (lower.match(/surge|soar|plunge|crash|dump|dumps|pump|pumps|spike|spikes|drop|drops|rally|rallies|\+\d{2}%|\-\d{2}%|up \d{1,2}%|down \d{1,2}%/i)) return 'price_movement';

  if (lower.match(/partnership|partners with|partner|integrat|integration|collaborat|collaboration|teams up|joins forces/i)) return 'partnership';

  if (lower.match(/upgrade|upgrades|hard fork|fork|mainnet|testnet|update|updates|launch|launches|deploys/i)) return 'upgrade';

  if (lower.match(/ethereum|\$eth\b|eth |vitalik|buterin|eip-|layer 2|l2/i)) return 'ethereum';

  if (lower.match(/bitcoin|\$btc\b|btc |satoshi|nakamoto|lightning network|taproot|ordinals/i)) return 'bitcoin';

  return 'other';
}

function calculateScore(tweet) {
  const metrics = tweet.public_metrics || {};
  const likes = metrics.like_count || 0;
  const retweets = metrics.retweet_count || 0;
  const replies = metrics.reply_count || 0;

  let score = (likes * 1) + (retweets * 3) + (replies * 2);

  const ageHours = (Date.now() - new Date(tweet.created_at).getTime()) / (1000 * 60 * 60);
  const freshness = Math.max(0, 100 - (ageHours * 10));
  score += freshness;

  const textOriginal = tweet.text || '';
  const text = textOriginal.toLowerCase();

  // ----------------------------------------------------------------
  // Смысловые признаки и штрафы.
  // Даже если мусорный твит не был отрезан фильтром, он не должен побеждать.
  // ----------------------------------------------------------------

  const meaningfulWordCount = getMeaningfulWordCount(textOriginal);
  const mentionCount = getMentionCount(textOriginal);
  const urlCount = getUrlCount(textOriginal);

  if (meaningfulWordCount < 4) score -= 500;
  if (mentionCount >= 2) score -= 150;
  if (urlCount > 0 && meaningfulWordCount < 6) score -= 200;

  if (/link in bio|telegram|follow along|entry and exit|exact chart|closed another trade|clean \+\d{2,4}% profit|\+\d{2,4}% profit|deposit \$?\d+|cashback|sign up with my link/i.test(textOriginal)) {
    score -= 1000;
  }

  // Старые бонусы за хайп-слова.
  ['pump', 'surge', 'rocket', 'moon', 'explode', 'breakout', 'rally'].forEach(keyword => {
    if (text.includes(keyword)) score += 100;
  });

  const tickerMatches = textOriginal.match(/\$[A-Z]{3,6}/g);
  if (tickerMatches) score += tickerMatches.length * 50;

  // НОВОЕ: небольшой бонус за наличие фактуры.
  // Не слишком большой, чтобы не поощрять длинные полотна.
  if (meaningfulWordCount >= 8) score += 40;
  if (meaningfulWordCount >= 15) score += 30;

  // НОВОЕ: бонус за цифры/данные. Такие твиты чаще дают материал для поста.
  if (/\d+(\.\d+)?%|\$\d+|\d+[kmb]\b|all-time high|7-year low|30 days|one month/i.test(textOriginal)) {
    score += 60;
  }

  return Math.round(score);
}

// 3. Распределение по тирам

const priorityGroups = { tier1: [], tier2: [], tier3: [], tier4: [] };

freshTweets.forEach(t => {
  const score = calculateScore(t);
  const topic = getTopic(t.text);
  const enriched = {
    ...t,
    score,
    topic,
    meaningful_text: cleanMeaningfulText(t.text),
    meaningful_word_count: getMeaningfulWordCount(t.text)
  };

  if (['memecoin', 'altcoin', 'scandal'].includes(topic)) {
    priorityGroups.tier1.push(enriched);
  } else if (['ath', 'etf', 'whale', 'regulation', 'institutional', 'listing'].includes(topic)) {
    priorityGroups.tier2.push(enriched);
  } else if (['price_movement', 'partnership', 'upgrade'].includes(topic)) {
    priorityGroups.tier3.push(enriched);
  } else {
    priorityGroups.tier4.push(enriched);
  }
});

// Берём лучшую доступную группу
let finalTweets = [];

if (priorityGroups.tier1.length > 0) {
  finalTweets = priorityGroups.tier1;
} else if (priorityGroups.tier2.length > 0) {
  finalTweets = priorityGroups.tier2;
} else if (priorityGroups.tier3.length > 0) {
  finalTweets = priorityGroups.tier3;
} else {
  finalTweets = priorityGroups.tier4;
}

// Сортируем топ по убыванию баллов
finalTweets.sort((a, b) => b.score - a.score);

// Если ничего не нашли
if (finalTweets.length === 0) {
  return [{
    json: {
      new_story_found: false,
      reason: 'No ranked candidates after junk filtering'
    }
  }];
}

// Режем массив до 5 элементов
const topCandidates = finalTweets.slice(0, 5);

// Возвращаем массив из элементов для цикла
return topCandidates.map(tweet => {
  // Ищем юзернейм автора по его ID
  const author = users.find(u => u.id === tweet.author_id);

  return {
    json: {
      new_story_found: true,
      selected_id: tweet.id,
      topic: tweet.topic,
      score: tweet.score,

      // НОВОЕ: диагностические поля.
      // Нужны, чтобы видеть, почему твит прошёл и сколько в нём смысла.
      meaningful_word_count: tweet.meaningful_word_count,
      meaningful_text: tweet.meaningful_text,

      prompt_text: tweet.text,
      author_username: author ? author.username : "unknown"
    }
  };
});

const mentionsData = $input.all();
const mentions = mentionsData
  .map(row => row.json.Handle)
  .filter(handle => handle && handle.trim() !== '')
  .filter(handle => handle.startsWith('@'));

const validMentionsString = mentions.join(', ');

console.log('✅ Mentions for GPT:', validMentionsString);

return [{
  json: {
    valid_mentions_string: validMentionsString,
    mentions_count: mentions.length,
  }
}]

const aiData = $json;
const sourceData = $('Loop Over Items').item.json;

return [{
  json: {
    ...aiData,
    original_tweet: sourceData.prompt_text || '',
    original_selected_id: sourceData.selected_id || '',
    original_topic: sourceData.topic || '',
    original_author_username: sourceData.author_username || ''
  }
}];

const sd = $getWorkflowStaticData('global');
const now = Date.now();

// ===== РУЧНЫЕ РУБИЛЬНИКИ =====
// true  = полностью отключить PROJECT_A_URL и все его приоритеты.
// false = включить PROJECT_A_URL и утренний приоритетный слот.
const PROJECT_A_URL_PAUSED_SWITCH = false;

// ===== PROJECT D CONFIG =====
const PROJECT_D_TZ = 'Europe/Moscow';
const PROJECT_D_DAY_START_HOUR = 10;
const PROJECT_D_DAY_END_HOUR = 21;
const PROJECT_D_MAX_PER_DAY = 2;

// ===== PROJECT A URL CONFIG =====
const PROJECT_A_URL_TZ = 'Europe/Moscow';

// 06:00 МСК – начало резерва слота Project A под URL.
// Если URL сегодня ещё не был, обычные run_project_a / run_project_a_mini с этого момента блокируются.
const PROJECT_A_URL_RESERVE_START_MIN = 6 * 60;

// 07:00 МСК – целевое время.
// С этого момента URL может выйти самостоятельно, даже если обычный Project A ещё не созрел.
const PROJECT_A_URL_TARGET_MIN = 7 * 60;

// 08:00 МСК – конец идеального окна.
// Это НЕ дедлайн. После 08:00 URL всё равно должен выйти при первой безопасной возможности.
const PROJECT_A_URL_IDEAL_END_MIN = 8 * 60;

// Минимальный разрыв от последнего Project A поста.
const PROJECT_A_URL_MIN_GAP_MS = 90 * 60 * 1000;

// ===== HELPERS =====
function getDayParts(ts, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).formatToParts(new Date(ts));

  const map = {};
  for (const p of parts) {
    if (p.type !== 'literal') map[p.type] = p.value;
  }

  const hour = Number(map.hour);
  const minute = Number(map.minute);

  return {
    dayKey: `${map.year}-${map.month}-${map.day}`,
    hour,
    minute,
    minuteOfDay: hour * 60 + minute,
  };
}

// ===== INIT =====
if (sd.PROJECT_A_NEXT_AT === undefined) sd.PROJECT_A_NEXT_AT = 0;
if (sd.PROJECT_A_MINI_NEXT_AT === undefined) sd.PROJECT_A_MINI_NEXT_AT = 0;
if (sd.PROJECT_B_NEXT_AT === undefined) sd.PROJECT_B_NEXT_AT = 0;
if (sd.PROJECT_C_NEXT_AT === undefined) sd.PROJECT_C_NEXT_AT = 0;

if (sd.PROJECT_B_POST_COUNT === undefined) sd.PROJECT_B_POST_COUNT = 0;
if (sd.PROJECT_C_POST_COUNT === undefined) sd.PROJECT_C_POST_COUNT = 0;

// Project A URL init
if (sd.PROJECT_A_URL_DAY_KEY === undefined) sd.PROJECT_A_URL_DAY_KEY = '';
if (sd.PROJECT_A_LAST_POST_AT === undefined) sd.PROJECT_A_LAST_POST_AT = 0;

// Применяем ручной рубильник.
// ВАЖНО: это намеренно перезаписывает static data при каждом запуске,
// чтобы изменение PROJECT_A_URL_PAUSED_SWITCH в коде сразу вступало в силу.
sd.PROJECT_A_URL_PAUSED = PROJECT_A_URL_PAUSED_SWITCH;

// Project D init
if (sd.PROJECT_D_NEXT_AT === undefined) sd.PROJECT_D_NEXT_AT = 0;
if (sd.PROJECT_D_DAY_KEY === undefined) sd.PROJECT_D_DAY_KEY = '';
if (sd.PROJECT_D_DAY_COUNT === undefined) sd.PROJECT_D_DAY_COUNT = 0;

// ===== ЕЖЕДНЕВНЫЙ СБРОС PROJECT D =====
const projectDTime = getDayParts(now, PROJECT_D_TZ);

if (sd.PROJECT_D_DAY_KEY !== projectDTime.dayKey) {
  sd.PROJECT_D_DAY_KEY = projectDTime.dayKey;
  sd.PROJECT_D_DAY_COUNT = 0;
}

// ===== PROJECT A / PROJECT A URL ОКНА =====
const projectATime = getDayParts(now, PROJECT_A_URL_TZ);

const raw_run_project_a = now >= sd.PROJECT_A_NEXT_AT;

const raw_run_project_a_mini =
  now >= sd.PROJECT_A_MINI_NEXT_AT &&
  now < sd.PROJECT_A_NEXT_AT;

const project_a_url_paused = sd.PROJECT_A_URL_PAUSED === true;
const project_a_url_enabled = !project_a_url_paused;

const project_a_url_done_today =
  sd.PROJECT_A_URL_DAY_KEY === projectATime.dayKey;

const project_a_url_not_done =
  project_a_url_enabled &&
  !project_a_url_done_today;

const project_a_url_reserve_started =
  projectATime.minuteOfDay >= PROJECT_A_URL_RESERVE_START_MIN;

const project_a_url_target_reached =
  projectATime.minuteOfDay >= PROJECT_A_URL_TARGET_MIN;

const project_a_url_in_ideal_window =
  projectATime.minuteOfDay >= PROJECT_A_URL_RESERVE_START_MIN &&
  projectATime.minuteOfDay < PROJECT_A_URL_IDEAL_END_MIN;

const project_a_url_ideal_window_missed =
  projectATime.minuteOfDay >= PROJECT_A_URL_IDEAL_END_MIN &&
  project_a_url_not_done;

const project_a_url_gap_ok =
  now - sd.PROJECT_A_LAST_POST_AT >= PROJECT_A_URL_MIN_GAP_MS;

// С 06:00 и до публикации сегодняшнего URL
// весь Project A слот зарезервирован под URL.
const project_a_url_blocks_project_a_like =
  project_a_url_not_done &&
  project_a_url_reserve_started;

// В 06:00-08:00 URL может забрать созревший Project A слот,
// если обычный Project A или Mini уже созрели и разбег выдержан.
const project_a_like_slot_due =
  raw_run_project_a ||
  raw_run_project_a_mini;

const project_a_url_can_claim_reserved_slot =
  project_a_url_not_done &&
  project_a_url_reserve_started &&
  project_a_url_in_ideal_window &&
  project_a_like_slot_due &&
  project_a_url_gap_ok;

// С 07:00 URL может выйти самостоятельно,
// даже если обычный Project A ещё не созрел.
// После 08:00 это условие всё равно остаётся активным:
// если URL ещё не вышел, он выходит при первом безопасном разбеге.
const project_a_url_can_run_by_target =
  project_a_url_not_done &&
  project_a_url_target_reached &&
  project_a_url_gap_ok;

let run_project_a = false;
let run_project_a_url = false;

// Приоритет URL:
// 1) с 06:00 до 08:00 он может забрать созревший слот Project A;
// 2) с 07:00 он может выйти самостоятельно;
// 3) после 08:00 он всё равно обязан выйти при первом безопасном gap.
if (
  project_a_url_can_claim_reserved_slot ||
  project_a_url_can_run_by_target
) {
  run_project_a_url = true;
  run_project_a = false;

} else if (project_a_url_blocks_project_a_like) {
  // С 06:00 до выхода сегодняшнего URL обычный полноценный Project A не выпускаем.
  run_project_a_url = false;
  run_project_a = false;

} else if (raw_run_project_a) {
  // Обычный Project A работает только:
  // - до 06:00;
  // - если URL уже был сегодня;
  // - если URL-логика выключена рубильником.
  run_project_a = true;
  run_project_a_url = false;
}

// Project A Mini тоже блокируется утренним URL-резервом.
// Если URL-логика выключена, Mini работает как раньше.
const run_project_a_mini =
  !run_project_a_url &&
  !project_a_url_blocks_project_a_like &&
  raw_run_project_a_mini;

// ===== ПРОЧИЕ ОКНА =====
const run_project_b = now >= sd.PROJECT_B_NEXT_AT;
const run_project_c = now >= sd.PROJECT_C_NEXT_AT;

const project_d_daytime =
  projectDTime.hour >= PROJECT_D_DAY_START_HOUR &&
  projectDTime.hour < PROJECT_D_DAY_END_HOUR;

const run_project_d =
  project_d_daytime &&
  sd.PROJECT_D_DAY_COUNT < PROJECT_D_MAX_PER_DAY &&
  now >= sd.PROJECT_D_NEXT_AT;

// Генерация нужна, если открыт хотя бы один слот
const can_generate =
  run_project_a ||
  run_project_a_url ||
  run_project_a_mini ||
  run_project_b ||
  run_project_c ||
  run_project_d;

return [{
  json: {
    can_generate,

    run_project_a,
    run_project_a_url,
    run_project_a_mini,
    run_project_b,
    run_project_c,
    run_project_d,

    now,

    // Дебаг Project A
    raw_run_project_a,
    raw_run_project_a_mini,

    // Дебаг Project A URL
    project_a_url_enabled,
    project_a_url_paused,
    project_a_url_done_today,
    project_a_url_not_done,
    project_a_url_day_key: sd.PROJECT_A_URL_DAY_KEY,
    project_a_url_current_day_key: projectATime.dayKey,
    project_a_url_hour: projectATime.hour,
    project_a_url_minute: projectATime.minute,
    project_a_url_minute_of_day: projectATime.minuteOfDay,

    project_a_url_reserve_started,
    project_a_url_target_reached,
    project_a_url_in_ideal_window,
    project_a_url_ideal_window_missed,
    project_a_url_gap_ok,
    project_a_url_blocks_project_a_like,
    project_a_like_slot_due,
    project_a_url_can_claim_reserved_slot,
    project_a_url_can_run_by_target,

    project_a_last_post_at: sd.PROJECT_A_LAST_POST_AT,
    project_a_next_at: sd.PROJECT_A_NEXT_AT,
    project_a_mini_next_at: sd.PROJECT_A_MINI_NEXT_AT,

    // Дебаг Project D
    project_d_day_key: sd.PROJECT_D_DAY_KEY,
    project_d_day_count: sd.PROJECT_D_DAY_COUNT,
    project_d_daytime,
  }
}];

const sd = $getWorkflowStaticData('global');
const now = Date.now();

// ===== PROJECT D CONFIG =====
const PROJECT_D_TZ = 'Europe/Moscow';
const PROJECT_D_DAY_START_HOUR = 10;
const PROJECT_D_DAY_END_HOUR = 21;
const PROJECT_D_MAX_PER_DAY = 2;

// После поста Project D ждёт 3.5-5.5 часов.
// Но дневной лимит всё равно жёстко ограничивает максимум 2 поста.
const PROJECT_D_BASE_COOLDOWN_MS = 3.5 * 60 * 60 * 1000;
const PROJECT_D_RANDOM_COOLDOWN_MS = 2 * 60 * 60 * 1000;

// ===== PROJECT A URL CONFIG =====
const PROJECT_A_URL_TZ = 'Europe/Moscow';

// ===== HELPERS =====
function getDayParts(ts, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).formatToParts(new Date(ts));

  const map = {};
  for (const p of parts) {
    if (p.type !== 'literal') map[p.type] = p.value;
  }

  const hour = Number(map.hour);
  const minute = Number(map.minute);

  return {
    dayKey: `${map.year}-${map.month}-${map.day}`,
    hour,
    minute,
    minuteOfDay: hour * 60 + minute,
  };
}

// ===== READ CONTEXT =====
const pre = $('Content Pre-Gate').first().json;
const merged = $('Merge Winner Context').item.json;

// ===== INIT =====
if (sd.PROJECT_B_POST_COUNT === undefined) sd.PROJECT_B_POST_COUNT = 0;
if (sd.PROJECT_C_POST_COUNT === undefined) sd.PROJECT_C_POST_COUNT = 0;

// Глобальный счетчик для сквозного чередования режимов Project D
if (sd.PROJECT_D_POST_COUNT === undefined) sd.PROJECT_D_POST_COUNT = 0;

if (sd.PROJECT_A_NEXT_AT === undefined) sd.PROJECT_A_NEXT_AT = 0;
if (sd.PROJECT_A_MINI_NEXT_AT === undefined) sd.PROJECT_A_MINI_NEXT_AT = 0;
if (sd.PROJECT_B_NEXT_AT === undefined) sd.PROJECT_B_NEXT_AT = 0;
if (sd.PROJECT_C_NEXT_AT === undefined) sd.PROJECT_C_NEXT_AT = 0;

// Project A URL init
if (sd.PROJECT_A_URL_DAY_KEY === undefined) sd.PROJECT_A_URL_DAY_KEY = '';
if (sd.PROJECT_A_LAST_POST_AT === undefined) sd.PROJECT_A_LAST_POST_AT = 0;

// Fallback только для debug/безопасности.
// Рубильник управляется в Content Pre-Gate через PROJECT_A_URL_PAUSED_SWITCH.
if (sd.PROJECT_A_URL_PAUSED === undefined) sd.PROJECT_A_URL_PAUSED = true;

if (sd.PROJECT_D_NEXT_AT === undefined) sd.PROJECT_D_NEXT_AT = 0;
if (sd.PROJECT_D_DAY_KEY === undefined) sd.PROJECT_D_DAY_KEY = '';
if (sd.PROJECT_D_DAY_COUNT === undefined) sd.PROJECT_D_DAY_COUNT = 0;

// ===== DAILY RESET FOR PROJECT D =====
const projectDTime = getDayParts(now, PROJECT_D_TZ);

if (sd.PROJECT_D_DAY_KEY !== projectDTime.dayKey) {
  sd.PROJECT_D_DAY_KEY = projectDTime.dayKey;
  sd.PROJECT_D_DAY_COUNT = 0;
}

// ===== FLAGS FROM PRE-GATE =====
const run_project_a = !!pre.run_project_a;
const run_project_a_url = !!pre.run_project_a_url;
const run_project_a_mini = !!pre.run_project_a_mini;
const run_project_b = !!pre.run_project_b;
const run_project_c = !!pre.run_project_c;
const run_project_d = !!pre.run_project_d;

if (
  !run_project_a &&
  !run_project_a_url &&
  !run_project_a_mini &&
  !run_project_b &&
  !run_project_c &&
  !run_project_d
) {
  return [{
    json: {
      run_project_a: false,
      run_project_a_url: false,
      run_project_a_mini: false,
      run_project_b: false,
      run_project_c: false,
      run_project_d: false,
      skip_all: true,

      project_a_url_paused: sd.PROJECT_A_URL_PAUSED,
      project_a_url_day_key: sd.PROJECT_A_URL_DAY_KEY,
      project_a_last_post_at: sd.PROJECT_A_LAST_POST_AT,
      project_a_next_at: sd.PROJECT_A_NEXT_AT,
      project_a_mini_next_at: sd.PROJECT_A_MINI_NEXT_AT,
    }
  }];
}

// ===== ANTI-COLLISION DELAYS =====
let delay_project_b_min = 0;
let delay_project_c_min = 0;
let delay_project_d_min = 0;

// URL Project A считается таким же важным событием, как полноценный Project A,
//  и Project A Mini.
const projectALikeEvent =
  run_project_a ||
  run_project_a_url ||
  run_project_a_mini;

if (projectALikeEvent) {
  if (run_project_b) {
    delay_project_b_min = Math.floor(Math.random() * 15) + 15; // 15-29
  }

  if (run_project_c) {
    delay_project_c_min = Math.floor(Math.random() * 20) + 45; // 45-64
  }

  if (run_project_d) {
    delay_project_d_min = Math.floor(Math.random() * 25) + 75; // 75-99
  }
} else {
  if (run_project_b && run_project_c) {
    delay_project_c_min = Math.floor(Math.random() * 15) + 20; // 20-34
  }

  if (run_project_d) {
    if (run_project_b && run_project_c) {
      delay_project_d_min = Math.floor(Math.random() * 20) + 55; // 55-74
    } else if (run_project_b || run_project_c) {
      delay_project_d_min = Math.floor(Math.random() * 20) + 30; // 30-49
    }
  }
}

// ===== PROJECT A MINI =====
if (run_project_a_mini && !run_project_a && !run_project_a_url) {
  sd.PROJECT_A_MINI_NEXT_AT = sd.PROJECT_A_NEXT_AT;

  // Если mini реально публикует пост, фиксируем последний Project A-like пост.
  // Это нужно, чтобы URL-пост не вышел слишком близко к mini.
  sd.PROJECT_A_LAST_POST_AT = now;
}

// ===== FULL PROJECT A / PROJECT A URL =====
if (run_project_a || run_project_a_url) {
  const projectACooldown =
    (6.5 * 60 * 60 * 1000) +
    Math.floor(Math.random() * 30 * 60 * 1000);

  // Важно:
  // run_project_a_url считается полноценным Project A постом.
  // После него весь Project A-график начинается заново.
  sd.PROJECT_A_NEXT_AT = now + projectACooldown;
  sd.PROJECT_A_MINI_NEXT_AT = now + (projectACooldown / 2);

  // Фиксируем любой full Project A-like пост.
  sd.PROJECT_A_LAST_POST_AT = now;
}

// ===== PROJECT A URL DAILY MARK =====
if (run_project_a_url) {
  const projectATime = getDayParts(now, PROJECT_A_URL_TZ);

  // Отмечаем, что URL-пост сегодня уже был.
  sd.PROJECT_A_URL_DAY_KEY = projectATime.dayKey;
}

// ===== PROJECT B =====
if (run_project_b) {
  sd.PROJECT_B_POST_COUNT++;
  sd.PROJECT_B_NEXT_AT =
    now + (7 * 60 * 60 * 1000) +
    Math.floor(Math.random() * 120 * 60 * 1000);
}

// ===== PROJECT C =====
if (run_project_c) {
  sd.PROJECT_C_POST_COUNT++;
  sd.PROJECT_C_NEXT_AT =
    now + (7.5 * 60 * 60 * 1000) +
    Math.floor(Math.random() * 120 * 60 * 1000);
}

// ===== PROJECT D =====
if (run_project_d) {
  sd.PROJECT_D_DAY_COUNT++;
  sd.PROJECT_D_POST_COUNT++;

  if (sd.PROJECT_D_DAY_COUNT >= PROJECT_D_MAX_PER_DAY) {
    // Лимит дня закрыт.
    // Следующий запуск сможет пройти только после дневного сброса в Pre-Gate.
    // NEXT_AT всё равно ставим вперёд, чтобы не было постоянных ложных попыток в этот же день.
    sd.PROJECT_D_NEXT_AT =
      now + (12 * 60 * 60 * 1000);
  } else {
    sd.PROJECT_D_NEXT_AT =
      now +
      PROJECT_D_BASE_COOLDOWN_MS +
      Math.floor(Math.random() * PROJECT_D_RANDOM_COOLDOWN_MS);
  }
}

// ===== MODES =====
const project_b_mode = (sd.PROJECT_B_POST_COUNT % 2 === 1) ? 'NEWS' : 'EDU';
const project_c_mode = (sd.PROJECT_C_POST_COUNT % 2 === 1) ? 'EDU' : 'NEWS';

// Project D начинает с EDU, если счетчик нечетный
const project_d_mode = (sd.PROJECT_D_POST_COUNT % 2 === 1) ? 'EDU' : 'NEWS';

const selectedId = merged.selected_id || merged.original_selected_id || '';

return [{
  json: {
    run_project_a,
    run_project_a_url,
    run_project_a_mini,
    run_project_b,
    run_project_c,
    run_project_d,

    project_b_mode,
    project_c_mode,
    project_d_mode,

    delay_project_b_min,
    delay_project_c_min,
    delay_project_d_min,

    original_tweet: merged.original_tweet || '',
    project_a_generated_post: merged.twitter || '',
    tweet_url: `https://x.com/i/web/status/${selectedId}`,

    project_b_post_count: sd.PROJECT_B_POST_COUNT,
    project_c_post_count: sd.PROJECT_C_POST_COUNT,
    project_d_post_count: sd.PROJECT_D_POST_COUNT,

    project_a_next_at: sd.PROJECT_A_NEXT_AT,
    project_a_mini_next_at: sd.PROJECT_A_MINI_NEXT_AT,
    project_a_last_post_at: sd.PROJECT_A_LAST_POST_AT,

    project_a_url_paused: sd.PROJECT_A_URL_PAUSED,
    project_a_url_day_key: sd.PROJECT_A_URL_DAY_KEY,

    project_d_day_key: sd.PROJECT_D_DAY_KEY,
    project_d_day_count: sd.PROJECT_D_DAY_COUNT,

    selected_id: selectedId,
    telegram: merged.telegram || '',
    reddit_title: merged.reddit_title || '',
    image_prompt: merged.image_prompt || ''
  }
}];

const items = $input.all();

if (!items.length) {
  return [];
}

const first = items[0].json;

const rows = Array.isArray(first)
  ? first
  : items.map(item => item.json);

return rows
  .filter(row => row.tweet_id)
  .map(row => ({
    json: {
      tweet_id: String(row.tweet_id).trim(),
      post_date: row.post_date || '',
      post_text: row.post_text || ''
    }
  }));
